// TestDoNotScheduleTaintsFilterFunc_NoScheduleNoTraffic tests that NoScheduleNoTraffic taint is included in the filter
func TestDoNotScheduleTaintsFilterFunc_NoScheduleNoTraffic(t *testing.T) {
	filterFunc := DoNotScheduleTaintsFilterFunc()

	testCases := []struct {
		name     string
		taint    v1.Taint
		expected bool
	}{
		{
			name: "NoSchedule taint should be included",
			taint: v1.Taint{
				Key:    "test",
				Value:  "value",
				Effect: v1.TaintEffectNoSchedule,
			},
			expected: true,
		},
		{
			name: "NoScheduleNoTraffic taint should be included",
			taint: v1.Taint{
				Key:    "test",
				Value:  "value",
				Effect: v1.TaintEffectNoScheduleNoTraffic,
			},
			expected: true,
		},
		{
			name: "NoExecute taint should be included",
			taint: v1.Taint{
				Key:    "test",
				Value:  "value",
				Effect: v1.TaintEffectNoExecute,
			},
			expected: true,
		},
		{
			name: "PreferNoSchedule taint should NOT be included",
			taint: v1.Taint{
				Key:    "test",
				Value:  "value",
				Effect: v1.TaintEffectPreferNoSchedule,
			},
			expected: false,
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			result := filterFunc(&tc.taint)
			if result != tc.expected {
				t.Errorf("Expected %v, got %v for taint effect %v", tc.expected, result, tc.taint.Effect)
			}
		})
	}
}

